let num = 15;
if (num < 10) {
  console.log('numは10未満です');
} else if (num < 20) {
  console.log('numは10以上20未満です'); // numは10以上20未満ですが出力される
} else {
  console.log('numは20以上です');
}

let a = true;
let b = true;
if (a && b) {
  console.log('aとbはともに真です'); // aとbはともに真ですが出力される
}

let day = 3;
switch (day) {
  case 1:
    console.log('Monday');
    break;
  case 2:
    console.log('Tuesday');
    break;
  case 3:
    console.log('Wednesday'); // Wednesdayが出力される
    break;
  case 4:
    console.log('Thursday');
    break;
  case 5:
    console.log('Friday');
    break;
  default:
    console.log('Weekend');
}

let variable = 'hello';
if (typeof variable === 'number') {
  console.log('This is a number.');
} else if (typeof variable === 'string') {
  console.log('This is a string.'); // This is a string.が出力される
} else {
  console.log('This is something else.');
}

